# ----------------------------
# SQLite (best-effort persistence)
# ----------------------------
DB_PATH = str(Path(__file__).resolve().parent / "helpdesk.db")


def db() -> sqlite3.Connection:
    conn = sqlite3.connect(DB_PATH, check_same_thread=False)
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS tickets (
          ticket_id TEXT PRIMARY KEY,
          created_at TEXT NOT NULL,
          category TEXT NOT NULL,
          urgency TEXT NOT NULL,
          summary TEXT NOT NULL,
          status TEXT NOT NULL
        )
        """
    )
    conn.commit()
    return conn


@dataclass
class Ticket:
    ticket_id: str
    created_at: str
    category: str
    urgency: str
    summary: str
    status: str


def tickets_load_sqlite(limit: int = 200) -> List[Ticket]:
    try:
        conn = db()
        cur = conn.cursor()
        cur.execute(
            """
            SELECT ticket_id, created_at, category, urgency, summary, status
            FROM tickets
            ORDER BY created_at DESC
            LIMIT ?
            """,
            (limit,),
        )
        rows = cur.fetchall()
        return [Ticket(*row) for row in rows]
    except Exception:
        return []


def ticket_insert_sqlite(t: Ticket) -> bool:
    try:
        conn = db()
        conn.execute(
            """
            INSERT OR REPLACE INTO tickets(ticket_id, created_at, category, urgency, summary, status)
            VALUES(?, ?, ?, ?, ?, ?)
            """,
            (t.ticket_id, t.created_at, t.category, t.urgency, t.summary, t.status),
        )
        conn.commit()
        return True
    except Exception:
        return False


def ticket_update_status_sqlite(ticket_id: str, status: str) -> None:
    try:
        conn = db()
        conn.execute("UPDATE tickets SET status=? WHERE ticket_id=?", (status, ticket_id))
        conn.commit()
    except Exception:
        pass


# ----------------------------
# Helpers
# ----------------------------
def now_str() -> str:
    return datetime.now().strftime("%Y-%m-%d %H:%M")


def new_ticket_id() -> str:
    return f"HD-{uuid.uuid4().hex[:8].upper()}"


def classify_category(text: str) -> str:
    t = text.lower()
    if any(k in t for k in ["password", "locked", "lockout", "reset", "login"]):
        return "Access / Password"
    if any(k in t for k in ["mfa", "2fa", "authenticator", "otp", "verification code"]):
        return "MFA / SSO"
    if any(k in t for k in ["vpn", "anyconnect", "globalprotect", "tunnel", "error 809"]):
        return "VPN"
    if any(k in t for k in ["wifi", "wi-fi", "wireless", "ssid"]):
        return "Wi‑Fi"
    if any(k in t for k in ["install", "software", "app", "license", "admin rights"]):
        return "Software"
    if any(k in t for k in ["printer", "print", "spool", "queue"]):
        return "Printer"
    if any(k in t for k in ["phish", "phishing", "suspicious email", "spam"]):
        return "Security (Phishing)"
    return "General"


def quick_steps(category: str) -> str:
    if category == "VPN":
        return "Try: 1) confirm internet works, 2) restart VPN app, 3) try hotspot vs Wi‑Fi."
    if category == "Wi‑Fi":
        return "Try: 1) forget network, 2) rejoin correct SSID, 3) restart laptop Wi‑Fi."
    if category == "Access / Password":
        return "Try: 1) reset password (if allowed), 2) wait 10–15 min if locked, 3) check caps/keyboard."
    if category == "MFA / SSO":
        return "Try: 1) check phone time, 2) switch method, 3) re-enroll if new phone."
    if category == "Software":
        return "Try: 1) check software portal, 2) note app+version, 3) request install approval if needed."
    if category == "Printer":
        return "Try: 1) power-cycle printer, 2) clear queue, 3) re-add printer if offline."
    if category == "Security (Phishing)":
        return "Do: 1) don’t click, 2) report via phishing workflow, 3) reset password if you entered it."
    return "Share the exact error text and what changed recently."


def context_line() -> str:
    p = st.session_state.profile
    bits = []
    if p.get("device"):
        bits.append(f"Device={p['device']}")
    if p.get("os"):
        bits.append(f"OS={p['os']}")
    if p.get("location"):
        bits.append(f"Location={p['location']}")
    return ", ".join(bits)


def assistant_typing(delay_s: float = 0.14) -> None:
    with st.chat_message("assistant"):
        ph = st.empty()
        for dots in ["", ".", "..", "..."]:
            ph.markdown(f"Thinking{dots}")
            time.sleep(delay_s)
        ph.empty()


def tickets_to_csv_bytes(tickets: List[Ticket]) -> bytes:
    buf = io.StringIO()
    w = csv.writer(buf)
    w.writerow(["ticket_id", "created_at", "category", "urgency", "status", "summary"])
    for t in tickets:
        w.writerow([t.ticket_id, t.created_at, t.category, t.urgency, t.status, t.summary])
    return buf.getvalue().encode("utf-8")


def tickets_to_json_bytes(tickets: List[Ticket]) -> bytes:
    return json.dumps([asdict(t) for t in tickets], indent=2).encode("utf-8")


def create_ticket(summary: str, urgency: str) -> Ticket:
    category = classify_category(summary)
    ctx = context_line()
    full_summary = summary.strip()
    if ctx:
        full_summary = f"{full_summary} | {ctx}"

    t = Ticket(
        ticket_id=new_ticket_id(),
        created_at=now_str(),
        category=category,
        urgency=urgency,
        summary=full_summary[:450],
        status="Open",
    )

    # Always update UI immediately (Tickets tab reads this)
    st.session_state.tickets.insert(0, t)
    st.session_state.last_created_ticket_id = t.ticket_id

    # Best-effort disk save
    st.session_state.last_persist_ok = ticket_insert_sqlite(t)
    return t


