with tab_tickets:
    st.markdown("#### 🎫 Tickets")

    if st.session_state.last_created_ticket_id:
        st.success(f"Latest ticket: {st.session_state.last_created_ticket_id}")

    tickets = st.session_state.tickets
    if not tickets:
        st.info("No tickets yet. In Chat, type **create ticket**.")
    else:
        dl1, dl2 = st.columns(2)
        with dl1:
            st.download_button(
                "⬇️ Download CSV",
                data=tickets_to_csv_bytes(tickets),
                file_name="helpdesk_tickets.csv",
                mime="text/csv",
                use_container_width=True,
            )
        with dl2:
            st.download_button(
                "⬇️ Download JSON",
                data=tickets_to_json_bytes(tickets),
                file_name="helpdesk_tickets.json",
                mime="application/json",
                use_container_width=True,
            )

        st.write("")

        f1, f2 = st.columns([2, 1])
        with f1:
            q = st.text_input("Search", placeholder="Search by ID / keyword")
        with f2:
            status_filter = st.selectbox("Status", ["All", "Open", "In Progress", "Waiting on User", "Resolved"], index=0)

        def matches(t: Ticket) -> bool:
            ok = True
            if status_filter != "All":
                ok = ok and (t.status == status_filter)
            if q.strip():
                qq = q.lower().strip()
                ok = ok and (qq in t.ticket_id.lower() or qq in t.summary.lower() or qq in t.category.lower())
            return ok

        shown = [t for t in tickets if matches(t)]
        st.caption(f"Showing {len(shown)} of {len(tickets)}")

        for t in shown[:25]:
            st.markdown(
                f"""
<div class="card">
  <div style="display:flex; justify-content:space-between; gap:12px; align-items:center;">
    <div><b>{t.ticket_id}</b> <span class="small-muted">• {t.created_at}</span></div>
    <div class="badge">Status: <b>{t.status}</b></div>
  </div>
  <div class="small-muted" style="margin-top:.25rem;">{t.category} • Urgency: {t.urgency}</div>
  <div style="margin-top:.55rem;">{t.summary}</div>
</div>
""",
                unsafe_allow_html=True,
            )
            st.write("")

        st.markdown("#### 🛠️ Update status")
        pick = st.selectbox("Ticket ID", [t.ticket_id for t in tickets], index=0)
        new_status = st.selectbox("New status", ["Open", "In Progress", "Waiting on User", "Resolved"], index=0)

        if st.button("Update", type="primary"):
            for i, t in enumerate(st.session_state.tickets):
                if t.ticket_id == pick:
                    st.session_state.tickets[i] = Ticket(
                        ticket_id=t.ticket_id,
                        created_at=t.created_at,
                        category=t.category,
                        urgency=t.urgency,
                        summary=t.summary,
                        status=new_status,
                    )
                    break

            ticket_update_status_sqlite(pick, new_status)
            st.toast(f"{pick} → {new_status}", icon="✅")
            st.rerun()
